if(typeof Click=="undefined"){Click={}}function validateCreditCardField(d,b,m,g,e,p){var h=validateTextField(d,m,g,e,p);if(h){return h}else{var q=document.getElementById(d);var r=q.value;var o=document.getElementById(b).value;if(r.length>0){var j="";for(var l=0;l<r.length;l++){var n=r.charAt(l);if(n!="="&&n!=" "){j=j+n}}r=j;var f=r.length;if(f<13){Click.setFieldErrorClass(q);return p[3]}var a=r.charAt(0);var k=r.charAt(1);var s=false;if(o=="VISA"){s=((f==16)||(f==13))&&(a=="4")}if(o=="MASTER"){s=(f==16)&&(a=="5")&&("12345".indexOf(k)>=0)}if(o=="AMEX"){s=(f==15)&&(a=="3")&&("47".indexOf(k)>=0)}if(o=="DINERS"){s=(f==14)&&(a=="3")&&("068".indexOf(k)>=0)}if(o=="DISCOVER"){s=(f==16)&&r.startsWith("6011")}if(!s){Click.setFieldErrorClass(q);return p[3]}}Click.setFieldValidClass(q);return null}}function validateEmailField(a,g,d,b,h){var e=validateTextField(a,g,d,b,h);if(e){return e}else{var j=document.getElementById(a);var k=j.value;var c=k.length;if(c>0){var f=k.indexOf("@");if(f<1||f==c-1){Click.setFieldErrorClass(j);return h[3]}if(!isLetterOrDigit(k.charAt(0))){Click.setFieldErrorClass(j);return h[3]}if(!isLetterOrDigit(k.charAt(c-1))){Click.setFieldErrorClass(j);return h[3]}}}Click.setFieldValidClass(j);return null}function validateNumberField(g,f,c,e,b){var d=document.getElementById(g);if(d){var a=d.value;if(a.length==0){if(f){Click.setFieldErrorClass(d);return b[0]}}else{if(a>e){Click.setFieldErrorClass(d);return b[2]}else{if(a<c){Click.setFieldErrorClass(d);return b[1]}}}Click.setFieldValidClass(d);return null}else{return"Field "+g+" not found."}}function validatePickList(d,c,a){var b=document.getElementById(d);if(b){if(b.options.length==0){if(c){Click.setFieldErrorClass(b);return a[0]}}Click.setFieldValidClass(b);return null}else{return"Field "+d+" not found."}}function validateRegexField(h,g,b,a,c,d){var f=validateTextField(h,g,b,a,d);if(f){return f}else{var e=document.getElementById(h);if(e.value.length==0||e.value.match(new RegExp(c))){Click.setFieldValidClass(e);return null}else{Click.setFieldErrorClass(e);return d[3]}}return null}function initMenu(){if(document.all&&document.getElementById){var b=document.getElementById("dmenu");if(b){for(i=0;i<b.childNodes.length;i++){var a=b.childNodes[i];if(a.nodeName=="LI"){a.onmouseover=function(){this.className+=" over"};a.onmouseout=function(){this.className=this.className.replace(" over","")}}}}}}function isLetter(a){return(((a>="a")&&(a<="z"))||((a>="A")&&(a<="Z")))}function isDigit(a){return((a>="0")&&(a<="9"))}function isLetterOrDigit(a){return(isLetter(a)||isDigit(a))}function pickListMove(f,e,d,b){var a=new Object();for(var c=0;c<f.options.length;c++){if(f.options[c].selected){a[f.options[c].value]=true}}pickListMoveItem(f,e,a,d,b)}function pickListMoveAll(e,d,c,b){var a=new Object();for(i=0;i<e.options.length;i++){a[e.options[i].value]=true}pickListMoveItem(e,d,a,c,b)}function pickListMoveItem(g,f,a,d,b){for(var c=0;c<d.options.length;c++){if(a[d.options[c].value]){d.options[c].selected=b}}for(var c=0;c<g.options.length;c++){if(a[g.options[c].value]){g.options[c]=null;c--}}var e=0;for(var c=0;c<d.options.length;c++){if(d.options[c].selected==b){f.options[e]=new Option(d.options[c].text,d.options[c].value);e++}}}Click.submitLinkAction=function(d,g){var f=Click.getUrlParams(d.href);if(f==null){return false}var c=document.getElementById(g);if(c==null){return false}for(var b=0;b<f.length;b++){var e=f[b];var a=document.createElement("input");a.setAttribute("type","hidden");a.setAttribute("name",e.name);a.setAttribute("value",e.value);c.appendChild(a)}c.submit();return false};Click.getUrlParams=function(a){if(a==null||a==""||a=="undefined"){return null}a=unescape(a);var g=a.indexOf("?");if(g==-1){return null}a=a.substring(g+1);var c=a.split("&");var e=new Array();for(var b=0;b<c.length;b++){var d=new Object();var f=c[b].indexOf("=");if(f>=0){d.name=c[b].substring(0,f);d.value=c[b].substring(f+1);e.push(d)}}return e};Click.getTabSheetNumber=function(c){var b=document.getElementById(c);if(!b){return 1}var a=b.parentNode;while(a&&!Click.isTabSheet(a)){a=a.parentNode}if(a){return a.getAttribute("id").substr(10)}return 1};Click.isTabSheet=function(a){if(!a){return false}var b=a.getAttribute("id");if(b){if(b.indexOf("tab-sheet-")>=0){return true}}return false};Click.validateTabbedForm=function(j,b,h,a){var d="";var c=null;for(i=0;i<j.length;i++){var k=j[i];if(k!=null){var g=k.lastIndexOf("|");var e=k.substring(0,g);var f=k.substring(g+1);if(c==null){c=f}d+='<tr class="errors"><td class="errors" align="';d+=h;if(a!=null){d+='" style="';d+=a}d+='">';d+='<a class="error" href="javascript:onShowTab(Click.getTabSheetNumber(\''+f+"'));setFocus('";d+=f;d+="');\">";d+=e;d+="</a>";d+="</td></tr>"}}if(d.length>0){d='<table class="errors">'+d+"</table>";document.getElementById(b+"-errorsDiv").innerHTML=d;document.getElementById(b+"-errorsTr").style.display="inline";setFocus(c);return false}else{return true}};